'use client';

import Image from 'next/image';
import Link from 'next/link';
import { useState } from 'react';
import { getProductById, getRelatedProducts } from '@/data/products';
import { useCart } from '@/contexts/CartContext';
import { CATEGORY_LABELS } from '@/types/shop';

export default function ProductDetail({ productId }: { productId: string }) {
  const [quantity, setQuantity] = useState(1);
  const [selectedImage, setSelectedImage] = useState(0);
  const [cartFeedback, setCartFeedback] = useState<string | null>(null);
  const { addItem } = useCart();
  const product = getProductById(productId);

  const handleAddToCart = () => {
    if (!product) {
      return;
    }

    addItem(product.id, quantity, product.price);
    setCartFeedback(`${quantity} product${quantity > 1 ? 'en' : ''} toegevoegd aan je winkelwagen.`);
    window.setTimeout(() => setCartFeedback(null), 2500);
  };

  if (!product) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-slate-50">
        <div className="text-center">
          <h2 className="mb-4 text-2xl font-bold text-slate-900">Product niet gevonden</h2>
          <Link href="/shop" className="text-sky-700 hover:underline">
            Terug naar shop
          </Link>
        </div>
      </div>
    );
  }

  const relatedProducts = getRelatedProducts(product, 3);
  const selectedProductImage = product.images[selectedImage] ?? product.images[0];

  return (
    <div className="min-h-screen bg-slate-50">
      <div className="container mx-auto px-4 py-8">
        <nav className="mb-8 text-sm">
          <Link href="/" className="text-sky-700 hover:underline">Home</Link>
          <span className="mx-2 text-slate-400">/</span>
          <Link href="/shop" className="text-sky-700 hover:underline">Shop</Link>
          <span className="mx-2 text-slate-400">/</span>
          <span className="text-slate-600">{product.name}</span>
        </nav>

        <div className="grid gap-12 lg:grid-cols-[1.05fr_0.95fr]">
          <div>
            <div className="overflow-hidden rounded-[2rem] border border-slate-200 bg-white shadow-sm">
              <div className="relative aspect-square bg-gradient-to-br from-slate-100 via-white to-sky-50">
                <Image
                  src={selectedProductImage}
                  alt={product.name}
                  fill
                  sizes="(max-width: 1024px) 100vw, 50vw"
                  className="object-contain p-10"
                />
              </div>
            </div>

            {product.images.length > 1 && (
              <div className="mt-4 grid grid-cols-2 gap-4 sm:grid-cols-4">
                {product.images.map((image, index) => (
                  <button
                    key={image}
                    type="button"
                    onClick={() => setSelectedImage(index)}
                    className={`relative overflow-hidden rounded-2xl border bg-white ${
                      selectedImage === index
                        ? 'border-sky-600 ring-4 ring-sky-100'
                        : 'border-slate-200'
                    }`}
                  >
                    <div className="relative aspect-square">
                      <Image
                        src={image}
                        alt={`${product.name} ${index + 1}`}
                        fill
                        sizes="160px"
                        className="object-contain p-4"
                      />
                    </div>
                  </button>
                ))}
              </div>
            )}
          </div>

          <div>
            <div className="mb-4 flex flex-wrap items-center gap-3 text-sm">
              <span className="rounded-full bg-sky-100 px-3 py-1 font-medium text-sky-800">
                {CATEGORY_LABELS[product.category]}
              </span>
              {product.brand && (
                <span className="rounded-full bg-slate-200 px-3 py-1 font-medium text-slate-700">
                  {product.brand}
                </span>
              )}
              {product.bestseller && (
                <span className="rounded-full bg-amber-100 px-3 py-1 font-medium text-amber-800">
                  Bestseller
                </span>
              )}
            </div>

            <h1 className="mb-4 text-3xl font-bold text-slate-900 md:text-4xl">{product.name}</h1>
            <p className="mb-6 text-lg leading-7 text-slate-600">{product.shortDescription}</p>

            <div className="mb-6 flex flex-wrap items-center gap-4">
              {product.originalPrice ? (
                <div>
                  <span className="mr-3 text-2xl text-slate-400 line-through">
                    €{product.originalPrice.toFixed(2)}
                  </span>
                  <span className="text-4xl font-bold text-rose-600">
                    €{product.price.toFixed(2)}
                  </span>
                  <span className="ml-3 rounded-full bg-rose-100 px-3 py-1 text-sm font-medium text-rose-800">
                    Bespaar €{(product.originalPrice - product.price).toFixed(2)}
                  </span>
                </div>
              ) : (
                <span className="text-4xl font-bold text-slate-900">
                  €{product.price.toFixed(2)}
                </span>
              )}
            </div>

            {product.inStock ? (
              <div className="mb-6 inline-block rounded-2xl bg-emerald-100 px-4 py-2 text-emerald-800">
                ✓ Op voorraad ({product.stockQuantity} stuks beschikbaar)
              </div>
            ) : (
              <div className="mb-6 inline-block rounded-2xl bg-rose-100 px-4 py-2 text-rose-800">
                Tijdelijk uitverkocht
              </div>
            )}

            <div className="mb-6 rounded-[2rem] border border-slate-200 bg-white p-6 shadow-sm">
              <h2 className="mb-3 text-lg font-bold">Productomschrijving</h2>
              <p className="mb-4 leading-7 text-slate-700">{product.description}</p>

              {product.features.length > 0 && (
                <div className="mt-4">
                  <h3 className="mb-2 font-semibold">Kenmerken:</h3>
                  <ul className="space-y-2">
                    {product.features.map((feature) => (
                      <li key={feature} className="flex items-start">
                        <span className="mr-2 text-emerald-600">✓</span>
                        <span className="text-slate-700">{feature}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              )}
            </div>

            {product.specifications && Object.keys(product.specifications).length > 0 && (
              <div className="mb-6 rounded-[2rem] border border-slate-200 bg-white p-6 shadow-sm">
                <h2 className="mb-3 text-lg font-bold">Specificaties</h2>
                <dl className="space-y-2">
                  {Object.entries(product.specifications).map(([key, value]) => (
                    <div key={key} className="flex justify-between gap-6 border-b border-slate-100 py-2">
                      <dt className="text-slate-600">{key}</dt>
                      <dd className="text-right font-medium text-slate-900">{value}</dd>
                    </div>
                  ))}
                  {product.weight && (
                    <div className="flex justify-between gap-6 border-b border-slate-100 py-2">
                      <dt className="text-slate-600">Gewicht</dt>
                      <dd className="text-right font-medium text-slate-900">{product.weight}g</dd>
                    </div>
                  )}
                  {product.sku && (
                    <div className="flex justify-between gap-6 py-2">
                      <dt className="text-slate-600">SKU</dt>
                      <dd className="text-right font-medium text-slate-900">{product.sku}</dd>
                    </div>
                  )}
                </dl>
              </div>
            )}

            <div className="rounded-[2rem] border border-slate-200 bg-white p-6 shadow-sm">
              <div className="mb-4 flex items-center gap-4">
                <label className="font-medium text-slate-700">Aantal:</label>
                <div className="flex items-center rounded-2xl border border-slate-300">
                  <button
                    onClick={() => setQuantity(Math.max(1, quantity - 1))}
                    className="px-4 py-2 transition-colors hover:bg-slate-100"
                  >
                    -
                  </button>
                  <input
                    type="number"
                    value={quantity}
                    onChange={(event) => setQuantity(Math.max(1, parseInt(event.target.value, 10) || 1))}
                    className="w-16 border-x border-slate-300 py-2 text-center"
                    min="1"
                  />
                  <button
                    onClick={() => setQuantity(quantity + 1)}
                    className="px-4 py-2 transition-colors hover:bg-slate-100"
                  >
                    +
                  </button>
                </div>
              </div>

              <button
                onClick={handleAddToCart}
                disabled={!product.inStock}
                className="mb-4 w-full rounded-2xl bg-slate-900 py-4 text-lg font-bold text-white transition-colors hover:bg-slate-800 disabled:cursor-not-allowed disabled:bg-slate-300"
              >
                {product.inStock ? 'Toevoegen aan winkelwagen' : 'Uitverkocht'}
              </button>

              {cartFeedback && (
                <div className="mb-4 rounded-2xl border border-emerald-200 bg-emerald-50 px-4 py-3 text-sm text-emerald-800">
                  {cartFeedback}
                </div>
              )}

              <Link href="/shop" className="mb-4 block w-full text-center text-sky-700 hover:underline">
                ← Terug naar shop
              </Link>

              <div className="mt-4 space-y-2 border-t border-slate-200 pt-4 text-sm text-slate-600">
                <p>✓ Gratis verzending vanaf €50</p>
                <p>✓ 14 dagen retourrecht</p>
                <p>✓ Veilig betalen</p>
                <p>✓ Besteld voor 15:00, morgen in huis</p>
              </div>
            </div>
          </div>
        </div>

        {relatedProducts.length > 0 && (
          <section className="mt-16">
            <div className="mb-6 flex items-end justify-between gap-4">
              <div>
                <p className="text-sm font-semibold uppercase tracking-[0.22em] text-sky-700">
                  Past hierbij
                </p>
                <h2 className="mt-2 text-2xl font-bold text-slate-900">Gerelateerde producten</h2>
              </div>
              <Link href="/shop" className="text-sm font-medium text-sky-700 hover:underline">
                Bekijk de volledige shop
              </Link>
            </div>

            <div className="grid gap-5 md:grid-cols-3">
              {relatedProducts.map((relatedProduct) => (
                <Link
                  key={relatedProduct.id}
                  href={`/shop/product/${relatedProduct.id}`}
                  className="overflow-hidden rounded-3xl border border-slate-200 bg-white shadow-sm transition hover:-translate-y-1 hover:shadow-lg"
                >
                  <div className="relative aspect-[4/3] bg-gradient-to-br from-slate-100 via-white to-sky-50">
                    <Image
                      src={relatedProduct.images[0]}
                      alt={relatedProduct.name}
                      fill
                      sizes="(max-width: 768px) 100vw, 33vw"
                      className="object-contain p-6"
                    />
                  </div>
                  <div className="p-5">
                    <h3 className="text-lg font-semibold text-slate-900">{relatedProduct.name}</h3>
                    <p className="mt-2 text-sm leading-6 text-slate-600">
                      {relatedProduct.shortDescription}
                    </p>
                    <p className="mt-4 text-lg font-bold text-slate-900">
                      €{relatedProduct.price.toFixed(2)}
                    </p>
                  </div>
                </Link>
              ))}
            </div>
          </section>
        )}
      </div>
    </div>
  );
}
